reference.source:
def fibonacci(n):
    if n == 0:
        return 0
    a, b = 0, 1
    for _ in range(2, n + 1):
        a, b = b, a + b
    return b

accepted_solutions.source:
def fibonacci(n, memo=None):
    if memo is None: memo = {0: 0, 1: 1}
    if n not in memo:
        memo[n] = fibonacci(n-1, memo) + fibonacci(n-2, memo)
    return memo[n]

